code = """import json
import re

# Load all NPM packages from packageinfo
package_file = locals()['var_functions.query_db:28']
if isinstance(package_file, str) and package_file.endswith('.json'):
    with open(package_file, 'r') as f:
        npm_packages = json.load(f)
else:
    npm_packages = package_file

print(f'Total NPM package versions: {len(npm_packages)}')

# Find latest version for each package (max ordinal)
latest_packages = {}
for pkg in npm_packages:
    name = pkg['Name']
    ordinal = int(pkg['Ordinal'])
    if name not in latest_packages or ordinal > latest_packages[name]['ordinal']:
        latest_packages[name] = {
            'name': name,
            'version': pkg['Version'],
            'ordinal': ordinal,
            'system': pkg['System']
        }

latest_list = list(latest_packages.values())
print(f'Distinct packages with latest versions: {len(latest_list)}')

# Load package-project mappings
mapping_file = locals()['var_functions.query_db:32']
if isinstance(mapping_file, str) and mapping_file.endswith('.json'):
    with open(mapping_file, 'r') as f:
        mappings = json.load(f)
else:
    mappings = mapping_file

# Create mapping dict: package -> project_name
project_map = {}
for m in mappings:
    if m['Name'].startswith('@discordx'):  # Just testing with discordx
        project_map[m['Name']] = m['ProjectName']

print(f'Project mappings for sample: {len(project_map)}')
print(project_map)

print('__RESULT__:')
print(json.dumps({'latest_discordx_count': len([p for p in latest_list if p['name'].startswith('@discordx')])}))"""

